15: // policyCache represents a cache of resolved policies for identities.
16: type policyCache struct {
17: 	lock.Mutex
18: 
19: 	// repo is a circular reference back to the Repository, but as
20: 	// we create only one Repository and one PolicyCache for each
21: 	// Cilium Agent process, these will never need to be garbage
22: 	// collected.
23: 	repo     *Repository
24: 	policies map[identityPkg.NumericIdentity]*cachedSelectorPolicy
25: }
26: 
27: // newPolicyCache creates a new cache of SelectorPolicy.
28: func newPolicyCache(repo *Repository, idmgr identitymanager.IDManager) *policyCache {
29: 	cache := &policyCache{
30: 		repo:     repo,
31: 		policies: make(map[identityPkg.NumericIdentity]*cachedSelectorPolicy),
32: 	}
33: 	if idmgr != nil {
34: 		idmgr.Subscribe(cache)
35: 	}
36: 	return cache
37: }
38: 
39: // lookupOrCreate adds the specified Identity to the policy cache, with a reference
40: // from the specified Endpoint, then returns the threadsafe copy of the policy.
41: func (cache *policyCache) lookupOrCreate(identity *identityPkg.Identity) *cachedSelectorPolicy {
42: 	cache.Lock()
43: 	defer cache.Unlock()
44: 	cip, ok := cache.policies[identity.ID]
45: 	if !ok {
46: 		cip = newCachedSelectorPolicy(identity)
47: 		cache.policies[identity.ID] = cip
48: 	}
49: 	return cip
50: }
51: 
52: // delete forgets about any cached SelectorPolicy that this endpoint uses.
53: //
54: // Returns true if the SelectorPolicy was removed from the cache.
55: func (cache *policyCache) delete(identity *identityPkg.Identity) bool {
56: 	cache.Lock()
57: 	defer cache.Unlock()
58: 	cip, ok := cache.policies[identity.ID]
59: 	if ok {
60: 		delete(cache.policies, identity.ID)
61: 		cip.getPolicy().Detach()
62: 	}
63: 	return ok
64: }
65: 
66: // updateSelectorPolicy resolves the policy for the security identity of the
67: // specified endpoint and stores it internally. It will skip policy resolution
68: // if the cached policy is already at the revision specified in the repo.
69: //
70: // Returns whether the cache was updated, or an error.
71: //
72: // Must be called with repo.Mutex held for reading.
73: func (cache *policyCache) updateSelectorPolicy(identity *identityPkg.Identity) (*selectorPolicy, bool, error) {
74: 	cip := cache.lookupOrCreate(identity)
75: 
76: 	// As long as UpdatePolicy() is triggered from endpoint
77: 	// regeneration, it's possible for two endpoints with the
78: 	// *same* identity to race to update the policy here. Such
79: 	// racing would lead to first of the endpoints using a
80: 	// selectorPolicy that is already detached from the selector
81: 	// cache, and thus not getting any incremental updates.
82: 	//
83: 	// Lock the 'cip' for the duration of the revision check and
84: 	// the possible policy update.
85: 	cip.Lock()
86: 	defer cip.Unlock()
87: 
88: 	// Don't resolve policy if it was already done for this or later revision.
89: 	if selPolicy := cip.getPolicy(); selPolicy != nil && selPolicy.Revision >= cache.repo.GetRevision() {
90: 		return selPolicy, false, nil
91: 	}
92: 
93: 	// Resolve the policies, which could fail
94: 	selPolicy, err := cache.repo.resolvePolicyLocked(identity)
95: 	if err != nil {
96: 		return nil, false, err
97: 	}
98: 
99: 	cip.setPolicy(selPolicy)
100: 
101: 	return selPolicy, true, nil
102: }
103: 
104: // LocalEndpointIdentityAdded is not needed; we only care about local endpoint
105: // deletion
106: func (cache *policyCache) LocalEndpointIdentityAdded(identity *identityPkg.Identity) {
107: }
108: 
109: // LocalEndpointIdentityRemoved deletes the cached SelectorPolicy for the
110: // specified Identity.
111: func (cache *policyCache) LocalEndpointIdentityRemoved(identity *identityPkg.Identity) {
112: 	cache.delete(identity)
113: }
114: 
115: // getAuthTypes returns the AuthTypes required by the policy between the localID and remoteID, if
116: // any, otherwise returns nil.
117: func (cache *policyCache) getAuthTypes(localID, remoteID identityPkg.NumericIdentity) AuthTypes {
118: 	cache.Lock()
119: 	cip, ok := cache.policies[localID]
120: 	cache.Unlock()
121: 	if !ok {
122: 		return nil // No policy for localID (no endpoint with localID)
123: 	}
124: 
125: 	// SelectorPolicy is const after it has been created, so no locking needed to access it
126: 	selPolicy := cip.getPolicy()
127: 
128: 	var resTypes AuthTypes
129: 	for cs, authTypes := range selPolicy.L4Policy.authMap {
130: 		missing := false
131: 		for authType := range authTypes {
132: 			if _, exists := resTypes[authType]; !exists {
133: 				missing = true
134: 				break
135: 			}
136: 		}
137: 		// Only check if 'cs' selects 'remoteID' if one of the authTypes is still missing
138: 		// from the result
139: 		if missing && cs.Selects(versioned.Latest(), remoteID) {
140: 			if resTypes == nil {
141: 				resTypes = make(AuthTypes, 1)
142: 			}
143: 			for authType := range authTypes {
144: 				resTypes[authType] = struct{}{}
145: 			}
146: 		}
147: 	}
148: 	return resTypes
149: }
150: 
151: // cachedSelectorPolicy is a wrapper around a selectorPolicy (stored in the
152: // 'policy' field). It is always nested directly in the owning policyCache,
153: // and is protected against concurrent writes via the policyCache mutex.
154: type cachedSelectorPolicy struct {
155: 	lock.Mutex // lock is needed to synchronize parallel policy updates
156: 
157: 	identity *identityPkg.Identity
158: 	policy   atomic.Pointer[selectorPolicy]
159: }
160: 
161: func newCachedSelectorPolicy(identity *identityPkg.Identity) *cachedSelectorPolicy {
162: 	cip := &cachedSelectorPolicy{
163: 		identity: identity,
164: 	}
165: 	return cip
166: }
167: 
168: // getPolicy returns a reference to the selectorPolicy that is cached.
169: //
170: // Users should treat the result as immutable state that MUST NOT be modified.
171: func (cip *cachedSelectorPolicy) getPolicy() *selectorPolicy {
172: 	return cip.policy.Load()
173: }
174: 
175: // setPolicy updates the reference to the SelectorPolicy that is cached.
176: // Calls Detach() on the old policy, if any.
177: func (cip *cachedSelectorPolicy) setPolicy(policy *selectorPolicy) {
178: 	oldPolicy := cip.policy.Swap(policy)
179: 	if oldPolicy != nil {
180: 		// Release the references the previous policy holds on the selector cache.
181: 		oldPolicy.Detach()
182: 	}
183: }
